/* Element selector */
p { color: #333; }

/* Class selector */
.tombol-utama { background: #3498db; color: white; }

/* ID selector */
#navbar { position: fixed; top: 0; }

/* Descendant selector: semua <a> di dalam <nav> */
nav a { text-decoration: none; color: white; }

/* Child selector: hanya <li> langsung di dalam <ul> */
ul > li { list-style: none; }

/* Attribute selector */
input[type='email'] { border: 2px solid #3498db; }

/* Multiple selector: terapkan ke h1, h2, dan h3 sekaligus */
h1, h2, h3 { font-family: 'Segoe UI', sans-serif; }

.kartu {
  /* Content */
  width: 300px;
  height: auto;

  /* Padding: ruang dalam */
  padding: 24px;              /* semua sisi sama */
  padding: 16px 24px;         /* atas-bawah | kiri-kanan */
  padding: 8px 16px 24px 12px; /* atas | kanan | bawah | kiri */

  /* Border */
  border: 2px solid #ddd;
  border-radius: 8px;         /* sudut membulat */

  /* Margin: jarak dari elemen lain */
  margin: 0 auto;             /* tengahkan elemen secara horizontal */
  margin-bottom: 24px;
}

/* Reset global — taruh di baris paling atas file CSS */
*, *::before, *::after {
  box-sizing: border-box;
}

/* Contoh perbedaannya: */
.kotak {
  width: 200px;
  padding: 20px;
  border: 5px solid black;
}

/* content-box: total lebar = 200 + 20+20 + 5+5 = 250px */
/* border-box:  total lebar = 200px (padding & border sudah termasuk) */

body {
  /* Tipografi dasar */
  font-family: 'Segoe UI', Roboto, Arial, sans-serif;
  font-size: 16px;         /* ukuran dasar */
  font-weight: 400;        /* 100-900, 400=normal, 700=bold */
  line-height: 1.6;        /* jarak antar baris, tanpa satuan = relatif */
  color: #2c3e50;
}

h1 {
  font-size: 2.5rem;       /* 2.5x ukuran root = 40px */
  font-weight: 700;
  letter-spacing: -0.5px;
  color: hsl(210, 30%, 20%);
}

.teks-muted {
  color: rgba(0, 0, 0, 0.5); /* hitam 50% transparan */
}

.highlight {
  background-color: #fff3cd;
  color: #856404;
}

.container {
  display: flex;

  /* Arah susunan item */
  flex-direction: row;           /* default: kiri ke kanan */
  /* flex-direction: column;     atas ke bawah */

  /* Perataan di main axis (horizontal jika row) */
  justify-content: flex-start;   /* default: kiri */
  justify-content: center;       /* tengah */
  justify-content: space-between;/* ujung ke ujung */
  justify-content: space-around; /* jarak merata */

  /* Perataan di cross axis (vertikal jika row) */
  align-items: stretch;          /* default: regangkan penuh */
  align-items: center;           /* tengah vertikal */
  align-items: flex-start;       /* rata atas */

  /* Biarkan item pindah baris jika tidak cukup ruang */
  flex-wrap: wrap;

  /* Jarak antar item */
  gap: 16px;
  gap: 16px 24px; /* baris | kolom */
}

.item {
  /* Kemampuan item untuk tumbuh mengisi ruang kosong */
  flex-grow: 1;    /* 0 = tidak tumbuh (default), 1 = tumbuh proporsional */

  /* Kemampuan item untuk menyusut jika ruang kurang */
  flex-shrink: 1;  /* default: boleh menyusut */

  /* Ukuran awal sebelum flex-grow/shrink diterapkan */
  flex-basis: 200px;

  /* Shorthand: grow | shrink | basis */
  flex: 1;         /* flex: 1 1 0 — paling umum dipakai */
  flex: 0 0 200px; /* ukuran tetap 200px, tidak tumbuh/menyusut */

  /* Override align-items khusus untuk item ini */
  align-self: flex-end;
}

.grid-container {
  display: grid;

  /* Definisi kolom: 3 kolom sama lebar */
  grid-template-columns: 1fr 1fr 1fr;
  grid-template-columns: repeat(3, 1fr);  /* shorthand yang sama */

  /* Definisi baris: baris pertama 80px, sisanya otomatis */
  grid-template-rows: 80px auto;

  /* Jarak antar sel */
  gap: 24px;

  /* Kolom responsif: auto-fit mengisi sebanyak mungkin kolom */
  /* dengan lebar minimum 250px */
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
}

/* Item yang menempati lebih dari satu kolom/baris */
.item-lebar {
  grid-column: 1 / 3;   /* dari kolom 1 sampai kolom 3 */
  grid-column: span 2;  /* rentangkan 2 kolom (shorthand) */
}

.item-tinggi {
  grid-row: 1 / 3;      /* dari baris 1 sampai baris 3 */
}

/* Navbar tetap di atas saat scroll */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 100;  /* tampil di atas elemen lain */
}

/* Parent untuk absolute positioning */
.kartu {
  position: relative;  /* jadikan anchor untuk elemen absolute di dalamnya */
}

/* Badge di pojok kanan atas kartu */
.badge {
  position: absolute;
  top: -8px;
  right: -8px;
}

/* Header tabel yang menempel saat scroll */
.header-tabel {
  position: sticky;
  top: 0;
  background: white;
}

/* Mobile-first approach: mulai dari mobile, tambah aturan untuk layar lebih besar */

/* Default: mobile */
.container {
  padding: 16px;
}

.grid {
  display: grid;
  grid-template-columns: 1fr;  /* 1 kolom di mobile */
  gap: 16px;
}

/* Tablet ke atas: min-width 768px */
@media (min-width: 768px) {
  .container {
    padding: 32px;
    max-width: 960px;
    margin: 0 auto;
  }

  .grid {
    grid-template-columns: repeat(2, 1fr);  /* 2 kolom di tablet */
    gap: 24px;
  }
}

/* Desktop ke atas: min-width 1024px */
@media (min-width: 1024px) {
  .grid {
    grid-template-columns: repeat(3, 1fr);  /* 3 kolom di desktop */
  }
}

/* Mode gelap sistem */
@media (prefers-color-scheme: dark) {
  body { background: #1a1a1a; color: #f0f0f0; }
}

/* Pseudo-class */
.tombol:hover {
  background: #2980b9;
  transform: translateY(-2px);
}

input:focus {
  outline: 2px solid #3498db;
  outline-offset: 2px;
}

tr:nth-child(even) {
  background: #f8f9fa;  /* warna zebra pada tabel */
}

/* Pseudo-element */
.artikel::first-letter {
  font-size: 3em;
  float: left;
  margin-right: 8px;
}

.wajib::after {
  content: ' *';
  color: red;
}

/* CSS Custom Properties (Variabel) */
:root {
  --warna-utama: #3498db;
  --warna-teks: #2c3e50;
  --border-radius: 8px;
  --bayangan: 0 2px 8px rgba(0,0,0,0.1);
}

.tombol {
  background: var(--warna-utama);
  border-radius: var(--border-radius);
  box-shadow: var(--bayangan);
}

/* Untuk ganti tema: cukup ubah variabelnya saja */
[data-tema='gelap'] {
  --warna-utama: #2ecc71;
  --warna-teks: #ecf0f1;
}

/* Transisi sederhana pada tombol */
.tombol {
  background: #3498db;
  color: white;
  padding: 12px 24px;
  border-radius: 6px;
  transition: background 0.3s ease, transform 0.2s ease;
}

.tombol:hover {
  background: #2980b9;
  transform: translateY(-3px);
}

.tombol:active {
  transform: translateY(0);
}

/* Transisi pada semua properti */
.kartu {
  transition: all 0.3s ease;
}
.kartu:hover {
  box-shadow: 0 8px 24px rgba(0,0,0,0.15);
  transform: translateY(-4px);
}

/* Animasi CSS dengan @keyframes */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.muncul {
  animation: fadeIn 0.5s ease forwards;
}

/* Animasi berulang: spinner loading */
@keyframes putar {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid #ddd;
  border-top-color: #3498db;
  border-radius: 50%;
  animation: putar 0.8s linear infinite;
}
